(window.webpackJsonp=window.webpackJsonp||[]).push([[607],{902:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val, next) {\\n *     this.val = (val===undefined ? 0 : val)\\n *     this.next = (next===undefined ? null : next)\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">list1</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">a</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">b</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">list2</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> mergeInBetween = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">list1, a, b, list2</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> preList1=list1\\n    <span class=\\"hljs-keyword\\">let</span> afxList1=list1\\n    <span class=\\"hljs-keyword\\">let</span> tailList2=list2\\n    <span class=\\"hljs-keyword\\">let</span> step=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">while</span>(tailList2.next){\\n        tailList2=tailList2.next\\n    }\\n    <span class=\\"hljs-keyword\\">while</span>(step&lt;a){\\n        preList1=preList1.next\\n        afxList1=afxList1.next\\n        step++\\n    }\\n    <span class=\\"hljs-keyword\\">while</span>(step&lt;=b+<span class=\\"hljs-number\\">1</span>){\\n        afxList1=afxList1.next\\n        step++\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(preList1,afxList1)</span>\\n    preList1.next=list2\\n\\n    tailList2.next=afxList1\\n    <span class=\\"hljs-keyword\\">return</span> list1\\n    \\n\\n};\\n</code></pre>\\n"],"titleSlug":"merge-in-between-linked-lists","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e24\u4e2a\u94fe\u8868\xa0<code>list1</code> \u548c\xa0<code>list2</code>\xa0\uff0c\u5b83\u4eec\u5305\u542b\u7684\u5143\u7d20\u5206\u522b\u4e3a\xa0<code>n</code> \u4e2a\u548c\xa0<code>m</code> \u4e2a\u3002</p>\\n\\n<p>\u8bf7\u4f60\u5c06\xa0<code>list1</code>\xa0\u4e2d\u7b2c\xa0<code>a</code>\xa0\u4e2a\u8282\u70b9\u5230\u7b2c\xa0<code>b</code>\xa0\u4e2a\u8282\u70b9\u5220\u9664\uff0c\u5e76\u5c06<code>list2</code>\xa0\u63a5\u5728\u88ab\u5220\u9664\u8282\u70b9\u7684\u4f4d\u7f6e\u3002</p>\\n\\n<p>\u4e0b\u56fe\u4e2d\u84dd\u8272\u8fb9\u548c\u8282\u70b9\u5c55\u793a\u4e86\u64cd\u4f5c\u540e\u7684\u7ed3\u679c\uff1a</p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/11/28/fig1.png\\" style=\\"height: 130px; width: 504px;\\" />\\n<p>\u8bf7\u4f60\u8fd4\u56de\u7ed3\u679c\u94fe\u8868\u7684\u5934\u6307\u9488\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/11/28/merge_linked_list_ex1.png\\" style=\\"width: 406px; height: 140px;\\" /></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>list1 = [0,1,2,3,4,5], a = 3, b = 4, list2 = [1000000,1000001,1000002]\\n<b>\u8f93\u51fa\uff1a</b>[0,1,2,1000000,1000001,1000002,5]\\n<b>\u89e3\u91ca\uff1a</b>\u6211\u4eec\u5220\u9664 list1 \u4e2d\u7b2c\u4e09\u548c\u7b2c\u56db\u4e2a\u8282\u70b9\uff0c\u5e76\u5c06 list2 \u63a5\u5728\u8be5\u4f4d\u7f6e\u3002\u4e0a\u56fe\u4e2d\u84dd\u8272\u7684\u8fb9\u548c\u8282\u70b9\u4e3a\u7b54\u6848\u94fe\u8868\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/11/28/merge_linked_list_ex2.png\\" style=\\"width: 463px; height: 140px;\\" />\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>list1 = [0,1,2,3,4,5,6], a = 2, b = 5, list2 = [1000000,1000001,1000002,1000003,1000004]\\n<b>\u8f93\u51fa\uff1a</b>[0,1,1000000,1000001,1000002,1000003,1000004,6]\\n<b>\u89e3\u91ca\uff1a</b>\u4e0a\u56fe\u4e2d\u84dd\u8272\u7684\u8fb9\u548c\u8282\u70b9\u4e3a\u7b54\u6848\u94fe\u8868\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>3 <= list1.length <= 10<sup>4</sup></code></li>\\n\\t<li><code>1 <= a <= b < list1.length - 1</code></li>\\n\\t<li><code>1 <= list2.length <= 10<sup>4</sup></code></li>\\n</ul>\\n","title":"1669. \u5408\u5e76\u4e24\u4e2a\u94fe\u8868","relatedTags":["\u94fe\u8868"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1669"}')}}]);